160→function base64ToBuffer(b64) {
161→	var str = b64.replace(/-/g, "+").replace(/_/g, "/");
162→	while (str.length % 4) str += "=";
163→	var bin = atob(str);
164→	var buf = new Uint8Array(bin.length);
165→	for (var i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
166→	return buf.buffer;
167→}
168→
169→function bufferToBase64(buf) {
170→	var bytes = new Uint8Array(buf);
171→	var str = "";
172→	for (var b of bytes) str += String.fromCharCode(b);
173→	return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
174→}
